sys_script.script:
(function executeRule(current, previous) {

    var status = current.getValue('status');

    if (status != 'draft') {

        gs.addErrorMessage(
            "This Plan cannot be deleted. Only draft plans can be deleted."
        );
        current.setAbortAction(true);
        return;
    }

    try {

        var planId = current.sys_id;

        //  function expression
        var deleteByPlan = function(tableName, logLabel) {

            var planRule = new GlideRecord(tableName);
            planRule.addQuery('plan', planId);
            planRule.setWorkflow(false);
            planRule.autoSysFields(false);
            planRule.query();

            var hasRecords = false;

            while (planRule.next()) {
                hasRecords = true;
                planRule.deleteRecord();
            }

            if (hasRecords) {
                gs.info("Deleted " + logLabel + " for plan: " + current.getDisplayValue());
            }
        };

        deleteByPlan('x_ctans_incentnow_payout_summary', 'Payout Summary');
        deleteByPlan('x_ctans_incentnow_lookup_rule', 'Lookup Rules');
        deleteByPlan('x_ctans_incentnow_earning_rule', 'Earning Rules');

        var credit = new GlideRecord('x_ctans_incentnow_credit_results');
        credit.addQuery('plan', planId);
        credit.deleteMultiple();

        var lookupRes = new GlideRecord('x_ctans_incentnow_lookup_results');
        lookupRes.addQuery('plan', planId);
        lookupRes.deleteMultiple();

        gs.info("Cascade delete completed for plan: " + current.getDisplayValue());

    } catch (ex) {

        gs.error("Error during cascade delete: " + ex.message);

        gs.addErrorMessage("Failed to delete related records. Contact admin.");
        current.setAbortAction(true);
    }

})(current, previous);
